import React from 'react';
import { useParams } from 'react-router-dom';
import { useCart } from '../hooks/useCart';

const ProductPage = () => {
  const { productId } = useParams<{ productId: string }>();
  const { addToCart } = useCart();

  const product = {
    id: productId,
    name: 'Apple',
    description: 'Fresh and juicy apples.',
    price: 1.99,
    image: 'https://images.unsplash.com/photo-1567306226416-28f0efdc88ce?w=400'
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-16">
      <div className="flex flex-col md:flex-row gap-8">
        <img src={product.image} alt={product.name} className="w-full md:w-1/2 rounded-xl shadow-md" />
        <div className="flex-1">
          <h2 className="text-3xl font-bold mb-4">{product.name}</h2>
          <p className="text-gray-400 mb-4">{product.description}</p>
          <p className="text-xl font-semibold mb-6">${product.price.toFixed(2)}</p>
          <button
            onClick={() => addToCart(product)}
            className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
          >
            Add to Cart
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductPage;

